  event: React.MouseEvent<HTMLButtonElement>
) => {
  event.stopPropagation();
  setIsLoading(true); // Démarre l'animation de chargement

  console.log('Début du processus d\'ajout au panier'); // Débogage

  // [...] Logique d'ajout au panier ici [...]

  // Le processus de vérification se passe bien et nous pouvons indiquer que l'article a été ajouté
  setIsAdded(true);
  console.log('Article ajouté'); // Débogage

  setTimeout(() => {
    console.log('Fin du délai, réinitialisation de l\'état isAdded'); // Débogage
    setIsAdded(false);
  }, 2000); // Ce délai doit correspondre à la durée de l'animation

  setIsLoading(false); // Cesse l'animation de chargement après la logique d'ajout au panier
  console.log('Fin du processus d\'ajout au panier, arrêt du chargement'); // Débogage
