      transition:{
        duration: 0.25,
        ease: [1, 0, 0,1]
      }
    }
  }

  const inputVariants = {
    hidden:{
      color:"#FFFFFF",
      transition:{
        duration: 0.25,
        ease: [1, 0, 0,1]
      }
    },
    visible:{
      color:"#E45A3B",
      transition:{
        duration: 0.25,
        ease: [1, 0, 0,1]
      }
    }
  }

  // const handleClick = () => {
  //   if(props.formRef){
  //     props.formRef.current?.requestSubmit()
  //   }
  // }

  return (
    <motion.div className='btn' 
    onClick = {props.onClick}
    onMouseEnter={() => setIsHovered(true)}
    onMouseLeave={() => setIsHovered(false)}
    variants={bgVariants}
    initial="hidden"
    animate={props.isLoading || isHovered ? "visible" : "hidden"}
    // onClick={handleClick}
    >

      <motion.input type="submit" value={props.text}
      variants={inputVariants}
      initial="hidden"
      animate={props.isLoading || isHovered ? "visible":"hidden"}
      onClick={(e) => e.preventDefault()}
      />

      <motion.img 
      src="/icones/right-arrow.svg" 
      alt="fleche vers la droite"
      variants={arrowVariants}
      initial="hidden"
      animate={props.isLoading ? "hiddenFromLoading" : isHovered ? "visible" : "hidden"} />

      <motion.svg
      variants={spinnerVariants}
      initial="hidden"
      animate={props.isLoading ? "loading" : "hidden"}
      width="43" height="43" viewBox="0 0 43 43" fill="none" xmlns="http://www.w3.org/2000/svg">
      <mask id="path-1-inside-1_1177_1978" fill="white">
      <path d="M8.22035 16.4431C7.61939 16.2224 6.9487 16.5299 6.77511 17.1461C5.97128 19.9994 6.0288 23.0366 6.95464 25.8709C8.00083 29.0736 10.0948 31.8309 12.8992 33.6984C15.7036 35.5658 19.0551 36.4348 22.4136 36.1652C25.772 35.8955 28.942 34.503 31.4125 32.2121C33.8831 29.9211 35.5104 26.8651 36.0322 23.5365C36.554 20.2079 35.94 16.8005 34.2891 13.8634C32.6382 10.9263 30.0465 8.63052 26.9316 7.34605C24.1751 6.20934 21.1509 5.92321 18.2452 6.50981C17.6176 6.63649 17.2605 7.28212 17.4353 7.898C17.61 8.51387 18.2505 8.86588 18.8797 8.74808C21.2823 8.29828 23.7729 8.55116 26.0478 9.48928C28.6813 10.5752 30.8724 12.5162 32.2682 14.9993C33.6639 17.4825 34.1831 20.3632 33.7419 23.1774C33.3007 25.9916 31.9249 28.5753 29.8362 30.5122C27.7474 32.4491 25.0675 33.6263 22.228 33.8543C19.3886 34.0822 16.5551 33.3476 14.1842 31.7687C11.8132 30.1899 10.0429 27.8588 9.15836 25.151C8.39427 22.8119 8.32972 20.3094 8.95921 17.9475C9.12408 17.3289 8.82131 16.6637 8.22035 16.4431Z"/>
      </mask>
      <path d="M8.22035 16.4431C7.61939 16.2224 6.9487 16.5299 6.77511 17.1461C5.97128 19.9994 6.0288 23.0366 6.95464 25.8709C8.00083 29.0736 10.0948 31.8309 12.8992 33.6984C15.7036 35.5658 19.0551 36.4348 22.4136 36.1652C25.772 35.8955 28.942 34.503 31.4125 32.2121C33.8831 29.9211 35.5104 26.8651 36.0322 23.5365C36.554 20.2079 35.94 16.8005 34.2891 13.8634C32.6382 10.9263 30.0465 8.63052 26.9316 7.34605C24.1751 6.20934 21.1509 5.92321 18.2452 6.50981C17.6176 6.63649 17.2605 7.28212 17.4353 7.898C17.61 8.51387 18.2505 8.86588 18.8797 8.74808C21.2823 8.29828 23.7729 8.55116 26.0478 9.48928C28.6813 10.5752 30.8724 12.5162 32.2682 14.9993C33.6639 17.4825 34.1831 20.3632 33.7419 23.1774C33.3007 25.9916 31.9249 28.5753 29.8362 30.5122C27.7474 32.4491 25.0675 33.6263 22.228 33.8543C19.3886 34.0822 16.5551 33.3476 14.1842 31.7687C11.8132 30.1899 10.0429 27.8588 9.15836 25.151C8.39427 22.8119 8.32972 20.3094 8.95921 17.9475C9.12408 17.3289 8.82131 16.6637 8.22035 16.4431Z" fill="#D9D9D9" stroke="#D9D9D9" stroke-width="8" mask="url(#path-1-inside-1_1177_1978)"/>
      </motion.svg>


      <motion.div className='anim-rectangle' 
      variants={animRectVariants}
      initial="hidden"
      animate={props.isLoading || isHovered ? "visible" : "hidden"}
      />

    </motion.div>
  )
}

Pour diminuer le padding du `Button` utilisé dans `TicketCard`, vous avez plusieurs options selon la façon dont votre code est structuré et si vous êtes prêt à ajuster `Button` pour être plus configurable ou non.

1. **Passer des styles personnalisés via les props**:
   Vous pouvez ajouter une prop `style` à votre composant `Button` qui permet de passer des styles personnalisés, notamment pour ajuster le padding.

   Dans `Button`:
   ```javascript
   type Prop = {
     // ... autres props
     style?: React.CSSProperties;
   };

   export default function Button(props: Prop) {
     // ... code existant

     return (
       <motion.div className='btn'
         style={props.style} // Utiliser le style personnalisé ici
         // ... autres props
       >
         {/* ... contenu du bouton */}
       </motion.div>
     )
   }
   ```

   Dans `TicketCard`, lorsque vous utilisez `Button`:
   ```javascript
   <Button
     text={isLoading ? "Chargement…" : isAdded ? "ARTICLE AJOUTÉ" : "AJOUT PANIER"}
     isLoading={isLoading}
     onClick={(event: React.MouseEvent<HTMLElement>) =>
       addToCartHandler(event as React.MouseEvent<HTMLButtonElement>)
     }
     style={{ padding: '10px 20px' }} // Exemple de valeur ajustée pour le padding
   />
   ```

2. **Modifier le CSS directement**:
   Si vous disposez d'un fichier CSS pour votre composant `Button`, vous pouvez simplement y ajuster le padding. Si vous avez besoin que le changement ne s'applique qu'à certains `Button` et pas à d'autres, vous pourriez passer une classe supplémentaire via les props et définir le style dans votre fichier CSS.

   Dans `Button.css` (ou tout autre fichier CSS correspondant):
   ```css
   .btn--small-padding {
     padding: 10px 20px; /* Vos valeurs de padding ajustées */
   }
   ```

   Dans le composant `Button`, ajoutez cette classe si nécessaire :
   ```javascript
   // ... code existant
   <motion.div className={`btn ${props.isSmallPadding ? 'btn--small-padding' : ''}`}
     // ... autres props
   >
     {/* ... contenu du bouton */}
   </motion.div>
   // ... code existant
   ```

   Et dans `TicketCard`, passez la nouvelle prop:
   ```javascript
   <Button
     // ... autres props
     isSmallPadding={true}
   />
   ```

3. **Utiliser un système de CSS-in-JS**:
   Si vous utilisez des bibliothèques comme `styled-components` ou `emotion`, vous pourriez créer une variante de votre bouton avec un padding spécifique pour cet usage.

Choisissez l'approche qui s'intègre le mieux à l'architecture actuelle de votre application. Il est également important de prendre en compte la réutilisabilité de votre composant de bouton; si vous vous attendez à avoir à personnaliser son style de manière similaire à de nombreux endroits, une approche avec `style` ou `className` props pourrait être plus maintenable à long terme.
